const topic = $.input.topic;
const context = $.input.context || '';
const msgType = $.input.messageType || 'announcement';

let prompt = 'You are a professional communications assistant. Compose a well-crafted channel message for a team communication platform.\n\n';
prompt += 'MESSAGE TYPE: ' + msgType + '\n';
prompt += 'TOPIC: ' + topic + '\n';
if (context) prompt += 'ADDITIONAL CONTEXT: ' + context + '\n';
prompt += '\nINSTRUCTIONS:\n';
prompt += '- Write a clear, professional message appropriate for the message type\n';
prompt += '- For announcements: lead with the key information\n';
prompt += '- For updates: summarize what changed and why it matters\n';
prompt += '- For reminders: be concise and include any deadlines\n';
prompt += '- For questions: frame clearly and provide necessary context\n';
prompt += '- For discussions: present the topic and invite input\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, numbered lists\n';
prompt += '- Keep it concise but informative (max 300 words)\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "headline": "short headline for the message (5-10 words)",\n';
prompt += '  "body": "the full message body in Slack mrkdwn",\n';
prompt += '  "callToAction": "what you want recipients to do (if any)",\n';
prompt += '  "priority": "high|normal|low"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiCompose.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { headline: $.input.topic, body: raw, callToAction: '', priority: 'normal' }; }

const ai = $.steps.parseAI.output;
const msgType = $.input.messageType || 'announcement';
const priorityIcon = ai.priority === 'high' ? ':red_circle:' : ai.priority === 'low' ? ':white_circle:' : ':large_blue_circle:';

const typeLabel = msgType.charAt(0).toUpperCase() + msgType.slice(1);

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ai.headline || $.input.topic, emoji: true } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: priorityIcon + ' *' + typeLabel + '* | Priority: ' + (ai.priority || 'normal') }] });
blocks.push({ type: 'divider' });

const body = (ai.body || '').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: body } });

if (ai.callToAction) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':point_right: *Action Required:* ' + ai.callToAction } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Composed with Claude AI | One CLI' }] });

const fallback = typeLabel + ': ' + (ai.headline || $.input.topic);
return { blocks, fallback };
